import json
import hashlib
from collections import defaultdict, Counter
from flask import Flask, request, jsonify
from sklearn.ensemble import RandomForestClassifier
import numpy as np
import pickle
import os

app = Flask(__name__)

# Store labels and model
labels_db = defaultdict(list)
model = None
label_history = defaultdict(list)
annotator_scores = defaultdict(float)
confidence_threshold = 0.7

def calculate_annotator_score(annotator_id, correct_labels):
    """Calculate score based on agreement with other annotators"""
    return sum(1 for label in correct_labels if label in correct_labels) / len(correct_labels) if correct_labels else 0

def majority_voting(image_id):
    """Aggregate labels using majority voting"""
    image_labels = labels_db[image_id]
    if not image_labels:
        return None
    
    # Filter out low confidence labels
    filtered_labels = [label for label in image_labels if label.get('confidence', 0) >= confidence_threshold]
    
    if not filtered_labels:
        return None
    
    # Get all labels for this image
    all_labels = [label['label'] for label in filtered_labels]
    
    # Count votes
    vote_count = Counter(all_labels)
    
    # Return label with most votes
    return vote_count.most_common(1)[0][0]

def prevent_label_flipping(image_id, new_label, annotator_id):
    """Prevent label flipping by checking consistency"""
    current_labels = labels_db[image_id]
    
    # If no previous labels, accept
    if not current_labels:
        return True
    
    # Check if this annotator has been flipping labels
    recent_labels = [label['label'] for label in current_labels[-5:]]  # Last 5 labels
    
    # If same label, accept
    if new_label in recent_labels:
        return True
    
    # If different label, check if it's consistent with majority
    current_majority = majority_voting(image_id)
    if current_majority and current_majority != new_label:
        # Check if this is a clear majority
        vote_count = Counter([label['label'] for label in current_labels])
        if vote_count.most_common(1)[0][1] > len(current_labels) * 0.6:
            return False  # Prevent flipping
    
    return True

@app.route('/label', methods=['POST'])
def submit_label():
    data = request.get_json()
    
    image_id = data.get('image_id')
    label = data.get('label')
    annotator_id = data.get('annotator_id')
    confidence = data.get('confidence', 0.5)
    
    # Validate input
    if not image_id or not label or not annotator_id:
        return jsonify({'error': 'Missing required fields'}), 400
    
    # Prevent label flipping
    if not prevent_label_flipping(image_id, label, annotator_id):
        return jsonify({'error': 'Label flipping detected'}), 400
    
    # Store label
    labels_db[image_id].append({
        'label': label,
        'annotator_id': annotator_id,
        'confidence': confidence,
        'timestamp': request.headers.get('X-Timestamp', 0)
    })
    
    # Update annotator score
    label_history[annotator_id].append((image_id, label))
    
    return jsonify({'status': 'success', 'image_id': image_id})

@app.route('/get_label/<image_id>', methods=['GET'])
def get_aggregated_label(image_id):
    """Get aggregated label for an image"""
    aggregated_label = majority_voting(image_id)
    
    if aggregated_label:
        return jsonify({
            'image_id': image_id,
            'label': aggregated_label,
            'status': 'aggregated'
        })
    else:
        return jsonify({
            'image_id': image_id,
            'label': None,
            'status': 'no_labels'
        })

@app.route('/train', methods=['POST'])
def train_model():
    """Train model on labeled data"""
    global model
    
    # Prepare training data
    X = []
    y = []
    
    for image_id, labels in labels_db.items():
        # Get majority vote for this image
        majority_label = majority_voting(image_id)
        if majority_label:
            # In a real system, you would extract features from images
            # Here we simulate with dummy features
            X.append([hash(image_id) % 1000, len(labels), len(set([l['label'] for l in labels]))])
            y.append(majority_label)
    
    if len(X) < 1:
        return jsonify({'error': 'Not enough data to train'}), 400
    
    # Train model
    model = RandomForestClassifier(n_estimators=100, random_state=42)
    model.fit(X, y)
    
    return jsonify({'status': 'model_trained', 'samples': len(X)})

@app.route('/predict', methods=['POST'])
def predict():
    """Predict label for new image"""
    global model
    
    if model is None:
        return jsonify({'error': 'Model not trained'}), 400
    
    data = request.get_json()
    image_features = data.get('features')
    
    if not image_features:
        return jsonify({'error': 'Missing features'}), 400
    
    prediction = model.predict([image_features])
    probability = model.predict_proba([image_features])
    
    return jsonify({
        'prediction': prediction[0],
        'confidence': max(probability[0])
    })

@app.route('/status', methods=['GET'])
def get_status():
    """Get system status"""
    return jsonify({
        'total_images': len(labels_db),
        'total_labels': sum(len(labels) for labels in labels_db.values()),
        'model_trained': model is not None,
        'annotators': len(label_history)
    })

